	for (int m = 0; m < 12; m++) n_lookups_per_material[m] = 0;
	for (int i = 0; i < in.lookups; i++) n_lookups_per_material[mat_samples[i]]++;

	qsort(pairs, (size_t)in.lookups, sizeof(MatEnergyPair), cmp_mat_then_e);

	int offset = 0;
	for (int m = 0; m < 12; m++)
	{
		if (n_lookups_per_material[m] > 1)
			qsort(pairs + offset, (size_t)n_lookups_per_material[m], sizeof(MatEnergyPair), cmp_e_only);
		offset += n_lookups_per_material[m];
	}

	for (int i = 0; i < in.lookups; i++)
	{
		mat_samples[i] = pairs[i].mat;
		p_energy_samples[i] = pairs[i].e;
	}

	offset = 0;
	unsigned long verification_scalar = 0;
	for (int m = 0; m < 12; m++)
	{
		int n_lookups = n_lookups_per_material[m];
		#pragma omp parallel for reduction(+:verification_scalar) schedule(static)
		for (int li = 0; li < n_lookups; li++)
		{
			int i = offset + li;
			int mat = mat_samples[i];
			if (mat != m) continue;

			double macro_xs[4] = {0};
			calculate_macro_xs(macro_xs, mat, p_energy_samples[i], in, SD);

			double max = -DBL_MAX;
			int max_idx = 0;
			for (int x = 0; x < 4; x++)
